import { ChangeDetectionStrategy, Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { MatButtonModule } from '@angular/material/button';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    MatButtonModule,
    MatCardModule,
    MatFormFieldModule,
    MatIconModule,
    MatInputModule,
    MatProgressSpinnerModule,
  ],
  template: `
    <div class="page-shell login-shell">
      <div class="ambient-orb orb-left"></div>
      <div class="ambient-orb orb-right"></div>

      <section class="hero-copy">
        <span class="pill">Hackathon Dashboard</span>
        <h1>AI Resource Allocation Optimizer</h1>
        <p>
          Assign work smarter, rebalance instantly, and visualize risk before delivery gets blocked.
        </p>

        <div class="benefits">
          <article>
            <mat-icon>auto_graph</mat-icon>
            <div>
              <h3>Performance feedback loop</h3>
              <p>Productivity scores evolve as outcomes improve or slip.</p>
            </div>
          </article>
          <article>
            <mat-icon>hub</mat-icon>
            <div>
              <h3>One-click rebalance</h3>
              <p>See safer assignments before applying them to the live plan.</p>
            </div>
          </article>
          <article>
            <mat-icon>dashboard_customize</mat-icon>
            <div>
              <h3>Customer-friendly presentation</h3>
              <p>Four-panel executive view tuned for a clean demo experience.</p>
            </div>
          </article>
        </div>
      </section>

      <mat-card class="login-card">
        <div class="brand-row">
          <div class="brand-badge">
            <mat-icon>hub</mat-icon>
          </div>
          <div>
            <h2>Welcome back</h2>
            <p>Use the seeded manager account for the full optimizer demo.</p>
          </div>
        </div>

        <form [formGroup]="loginForm" (ngSubmit)="submit()" class="login-form">
          <mat-form-field appearance="outline">
            <mat-label>Username</mat-label>
            <input matInput formControlName="username" autocomplete="username">
            <mat-icon matSuffix>person</mat-icon>
          </mat-form-field>

          <mat-form-field appearance="outline">
            <mat-label>Password</mat-label>
            <input matInput [type]="hidePassword() ? 'password' : 'text'" formControlName="password" autocomplete="current-password">
            <button mat-icon-button matSuffix type="button" (click)="hidePassword.set(!hidePassword())">
              <mat-icon>{{ hidePassword() ? 'visibility' : 'visibility_off' }}</mat-icon>
            </button>
          </mat-form-field>

          <button mat-flat-button color="primary" class="login-button" [disabled]="loading() || loginForm.invalid">
            <mat-spinner *ngIf="loading()" diameter="20"></mat-spinner>
            <span *ngIf="!loading()">Login to Dashboard</span>
          </button>
        </form>

        <div class="credential-box">
          <span>Demo credentials</span>
          <strong>manager / password</strong>
        </div>

        <p class="error-message" *ngIf="errorMessage()">{{ errorMessage() }}</p>
      </mat-card>
    </div>
  `,
  styles: [
    `
      .login-shell {
        display: grid;
        grid-template-columns: minmax(0, 1.1fr) minmax(360px, 440px);
        gap: 48px;
        align-items: center;
        padding: 48px clamp(24px, 4vw, 64px);
        min-height: 100vh;
        overflow: hidden;
      }

      .hero-copy {
        max-width: 680px;
        position: relative;
        z-index: 1;
      }

      .pill {
        display: inline-flex;
        padding: 10px 16px;
        border-radius: 999px;
        background: rgba(20, 99, 183, 0.14);
        color: var(--brand-dark);
        font-weight: 700;
        letter-spacing: 0.02em;
      }

      .hero-copy h1 {
        margin-top: 20px;
        font-size: clamp(2.8rem, 5vw, 4.4rem);
        line-height: 1.05;
      }

      .hero-copy p {
        margin: 18px 0 0;
        font-size: 1.08rem;
        color: var(--text-muted);
        line-height: 1.7;
        max-width: 620px;
      }

      .benefits {
        display: grid;
        gap: 18px;
        margin-top: 34px;
      }

      .benefits article {
        display: grid;
        grid-template-columns: 50px 1fr;
        gap: 16px;
        align-items: start;
        padding: 18px 20px;
        background: rgba(255, 255, 255, 0.72);
        border: 1px solid rgba(20, 99, 183, 0.08);
        border-radius: 20px;
        box-shadow: var(--shadow);
        backdrop-filter: blur(12px);
      }

      .benefits mat-icon {
        width: 50px;
        height: 50px;
        border-radius: 16px;
        display: grid;
        place-items: center;
        background: linear-gradient(145deg, rgba(20, 99, 183, 0.16), rgba(36, 160, 107, 0.16));
        color: var(--brand);
      }

      .benefits h3 {
        font-size: 1rem;
        margin-bottom: 6px;
      }

      .benefits p {
        margin: 0;
        font-size: 0.95rem;
      }

      .login-card {
        position: relative;
        z-index: 1;
        padding: 28px;
        border-radius: 28px;
        border: 1px solid rgba(20, 99, 183, 0.12);
        box-shadow: var(--shadow);
        background: rgba(255, 255, 255, 0.9);
        backdrop-filter: blur(16px);
      }

      .brand-row {
        display: grid;
        grid-template-columns: 60px 1fr;
        gap: 16px;
        align-items: center;
        margin-bottom: 24px;
      }

      .brand-badge {
        width: 60px;
        height: 60px;
        border-radius: 18px;
        display: grid;
        place-items: center;
        background: linear-gradient(135deg, var(--brand) 0%, #2e7dd3 100%);
        color: white;
      }

      .brand-row p {
        margin: 6px 0 0;
        color: var(--text-muted);
      }

      .login-form {
        display: grid;
        gap: 18px;
      }

      .login-button {
        height: 52px;
        border-radius: 16px;
        font-weight: 700;
      }

      .credential-box {
        margin-top: 20px;
        padding: 16px 18px;
        border-radius: 18px;
        background: linear-gradient(135deg, rgba(20, 99, 183, 0.1), rgba(36, 160, 107, 0.12));
        display: flex;
        justify-content: space-between;
        align-items: center;
        color: var(--brand-dark);
      }

      .credential-box span {
        font-size: 0.92rem;
      }

      .error-message {
        margin: 16px 0 0;
        color: var(--danger);
        font-weight: 600;
      }

      .ambient-orb {
        position: absolute;
        width: 320px;
        height: 320px;
        border-radius: 50%;
        filter: blur(28px);
        opacity: 0.4;
      }

      .orb-left {
        background: rgba(20, 99, 183, 0.22);
        top: -80px;
        left: -100px;
      }

      .orb-right {
        background: rgba(36, 160, 107, 0.2);
        right: -120px;
        bottom: 40px;
      }

      @media (max-width: 960px) {
        .login-shell {
          grid-template-columns: 1fr;
          padding-top: 28px;
        }
      }
    `,
  ],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class LoginComponent {
  private readonly fb = inject(FormBuilder);
  private readonly authService = inject(AuthService);
  private readonly router = inject(Router);

  readonly loading = signal(false);
  readonly errorMessage = signal('');
  readonly hidePassword = signal(true);

  readonly loginForm = this.fb.nonNullable.group({
    username: ['manager', Validators.required],
    password: ['password', [Validators.required, Validators.minLength(4)]],
  });

  submit() {
    if (this.loginForm.invalid || this.loading()) {
      return;
    }

    this.loading.set(true);
    this.errorMessage.set('');

    this.authService.login(this.loginForm.getRawValue()).subscribe({
      next: () => {
        this.loading.set(false);
        void this.router.navigate(['/dashboard']);
      },
      error: (error) => {
        this.loading.set(false);
        this.errorMessage.set(error?.error?.message ?? 'Unable to login. Please try again.');
      },
    });
  }
}
